import React, { useState, useEffect } from "react";
import {
  Star,
  CircleX,
  Archive,
  Trash2,
  Reply,
  Mail,
  MessagesSquare,
  MessageCircle,
  ArrowUpDown,
  ArrowUp,
  ArrowDown,
} from "lucide-react";
import logo from "../../../assets/images/capavate.png";
import ChatMessageAllModal from "../../social/company/ChatMessageAllModal";
import ChatMessageModal from "../../social/company/ChatMessageModal";
import {
  getUserConversations,
  initSocket,
  emitUserOnline,
  onNewMessageNamed,
  offNewMessageNamed,
  onUserStatusChange,
  emitCheckOnline,
  onOnlineStatus,
  removeAllListeners,
} from "../../../api/chatApi";
import axios from "axios";
import { API_BASE_URL } from "../../../config/config";

const dummyNotes = [
  {
    id: 1,
    name: "Avinay Kumar",
    role: "Shareholder",
    time: "10:32 AM",
    subject: "Query regarding Series A valuation",
    body: "Lorem ipsum dolor sit amet consectetur adipisicing elit.",
    important: true,
  },
];

export default function ShareholderMessages() {
  const [notes, setNotes] = useState(dummyNotes);
  const [selectedNote, setSelectedNote] = useState(null);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [showChatModal, setShowChatModal] = useState(false);
  const [selectedConvUser, setSelectedConvUser] = useState(null);
  const [conversations, setConversations] = useState([]);
  const [convLoading, setConvLoading] = useState(false);
  const [onlineUsers, setOnlineUsers] = useState(new Set());

  // ✅ New states for star + filter + sort
  const [starredIds, setStarredIds] = useState(new Set()); // starred conversation_ids
  const [activeTab, setActiveTab] = useState("all"); // "all" | "starred"
  const [sortOrder, setSortOrder] = useState("desc"); // "asc" | "desc"
  const [starLoading, setStarLoading] = useState(new Set()); // loading state per conv

  const storedUsername = localStorage.getItem("InvestorData");
  const userLogin = JSON.parse(storedUsername);
  const name = userLogin?.first_name + " " + userLogin?.last_name;

  const currentUser = {
    id: userLogin?.id,
    type: "investor",
    name: name,
    avatar: "",
  };

  const API_URL = `${API_BASE_URL}api/user/chatmessage`;

  useEffect(() => {
    if (!currentUser?.id) return;

    loadConversations();

    onUserStatusChange((data) => {
      const key = `${data.user_id}_${data.user_type}`;
      setOnlineUsers((prev) => {
        const next = new Set(prev);
        if (data.status === "online") next.add(key);
        else next.delete(key);
        return next;
      });
    });

    onOnlineStatus((data) => {
      const key = `${data.user_id}_${data.user_type}`;
      setOnlineUsers((prev) => {
        const next = new Set(prev);
        if (data.status === "online") next.add(key);
        else next.delete(key);
        return next;
      });
    });

    const registerListener = () => {
      onNewMessageNamed("investor-cards", (newMsg) => {
        newMsg.sender_id = Number(newMsg.sender_id);
        newMsg.receiver_id = Number(newMsg.receiver_id);

        setConversations((prev) => {
          let found = false;
          const updated = prev.map((conv) => {
            if (conv.conversation_id !== newMsg.conversation_id) return conv;
            found = true;
            const isMe = newMsg.sender_id === currentUser.id;
            const iAmReceiver = newMsg.receiver_id === currentUser.id;
            const amIP1 = conv.participant1_type === currentUser.type && Number(conv.participant1_id) === currentUser.id;
            const amIP2 = conv.participant2_type === currentUser.type && Number(conv.participant2_id) === currentUser.id;
            const unreadUpdate = iAmReceiver && !isMe ? {
              participant1_unread: amIP1 ? (conv.participant1_unread || 0) + 1 : conv.participant1_unread,
              participant2_unread: amIP2 ? (conv.participant2_unread || 0) + 1 : conv.participant2_unread,
            } : {};
            return {
              ...conv,
              last_message: newMsg.message || conv.last_message,
              last_message_time: newMsg.created_at || conv.last_message_time,
              ...unreadUpdate,
            };
          });
          if (!found) return prev;
          return [...updated].sort((a, b) =>
            new Date(b.last_message_time || b.updated_at) - new Date(a.last_message_time || a.updated_at)
          );
        });
      });
    };

    registerListener();

    initSocket(() => {
      emitUserOnline(currentUser.id, currentUser.type, currentUser.name);
      registerListener();
    });

    return () => {
      offNewMessageNamed("investor-cards");
      removeAllListeners(["user-status-change", "online-status"]);
    };
  }, [currentUser?.id]);

  const handleCloseChat = () => {
    setSelectedConvUser(null);
    loadConversations();
  };

  const handleCloseChatAll = () => {
    setShowChatModal(false);
    loadConversations();
  };

  const loadConversations = async () => {
    setConvLoading(true);
    try {
      const res = await getUserConversations(currentUser.type, currentUser.id);
      if (res.success) {
        const seen = new Map();
        res.conversations.forEach((conv) => {
          const key = `${conv.other_user_type}_${conv.other_user_id}`;
          const existing = seen.get(key);
          if (!existing || new Date(conv.updated_at) > new Date(existing.updated_at)) {
            seen.set(key, conv);
          }
        });
        const deduplicated = Array.from(seen.values())
          .sort((a, b) => new Date(b.updated_at) - new Date(a.updated_at))
          .slice(0, 10);
        setConversations(deduplicated);
        deduplicated.forEach((conv) => {
          emitCheckOnline(conv.other_user_id, conv.other_user_type);
        });

        // ✅ Load starred conversations
        await loadStarred();
      }
    } catch (err) {
      console.error("loadConversations error:", err);
    } finally {
      setConvLoading(false);
    }
  };

  // ✅ Load starred conversation ids for current user
  const loadStarred = async () => {
    try {
      const res = await axios.post(`${API_URL}/starred-conversations`, {
        starred_by_id: currentUser.id,
        starred_by_type: currentUser.type,
      });
      if (res.data.success) {
        setStarredIds(new Set(res.data.starred_ids));
      }
    } catch (err) {
      console.error("loadStarred error:", err);
    }
  };

  // ✅ Toggle star on conversation
  const handleStarConv = async (e, convId) => {
    e.stopPropagation(); // card click rok

    if (starLoading.has(convId)) return;

    // Optimistic update
    setStarredIds((prev) => {
      const next = new Set(prev);
      if (next.has(convId)) next.delete(convId);
      else next.add(convId);
      return next;
    });

    setStarLoading((prev) => new Set(prev).add(convId));

    try {
      await axios.post(`${API_URL}/star-conversation`, {
        conversation_id: convId,
        starred_by_id: currentUser.id,
        starred_by_type: currentUser.type,
      });
    } catch (err) {
      // Revert on error
      setStarredIds((prev) => {
        const next = new Set(prev);
        if (next.has(convId)) next.delete(convId);
        else next.add(convId);
        return next;
      });
    } finally {
      setStarLoading((prev) => {
        const next = new Set(prev);
        next.delete(convId);
        return next;
      });
    }
  };

  // ✅ Filtered + sorted conversations
  const displayedConversations = conversations
    .filter((conv) => activeTab === "all" || starredIds.has(conv.conversation_id))
    .sort((a, b) => {
      // ✅ Starred conversations hamesha top pe
      const aStarred = starredIds.has(a.conversation_id);
      const bStarred = starredIds.has(b.conversation_id);
      if (aStarred && !bStarred) return -1;
      if (!aStarred && bStarred) return 1;

      // ✅ Same star status hone pe date se sort
      const timeA = new Date(a.last_message_time || a.updated_at);
      const timeB = new Date(b.last_message_time || b.updated_at);
      return sortOrder === "desc" ? timeB - timeA : timeA - timeB;
    });

  const parseTimestamp = (ts) => {
    if (!ts) return new Date();
    if (ts instanceof Date) return ts;
    const s = ts.toString().trim();
    if (s.includes("Z") || s.match(/[+-]\d{2}:\d{2}$/)) return new Date(s);
    return new Date(s.replace(" ", "T") + "Z");
  };

  const formatTime = (ts) => {
    if (!ts) return "";
    const d = parseTimestamp(ts);
    const now = new Date();
    const diff = Math.round(
      (new Date(now.getFullYear(), now.getMonth(), now.getDate()) -
        new Date(d.getFullYear(), d.getMonth(), d.getDate())) / 86400000
    );
    if (diff === 0) return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", hour12: true });
    if (diff === 1) return "Yesterday";
    if (diff < 7) return d.toLocaleDateString([], { weekday: "short" });
    return d.toLocaleDateString([], { day: "2-digit", month: "short" });
  };

  const getRoleColor = (role) => {
    if (role === "company") return "#ff3e43";
    if (role === "investor") return "#22c55e";
    if (role === "admin") return "#9c27b0";
    return "#6c757d";
  };

  const getUnreadCount = (conv) => {
    const amIP1 = conv.participant1_type === currentUser.type && Number(conv.participant1_id) === currentUser.id;
    const amIP2 = conv.participant2_type === currentUser.type && Number(conv.participant2_id) === currentUser.id;
    if (amIP1) return conv.participant1_unread || 0;
    if (amIP2) return conv.participant2_unread || 0;
    return 0;
  };

  const isOnline = (userId, userType) => onlineUsers.has(`${userId}_${userType}`);

  const handleCardClick = (conv) => {
    setConversations((prev) =>
      prev.map((c) =>
        c.conversation_id === conv.conversation_id
          ? { ...c, participant1_unread: 0, participant2_unread: 0 }
          : c
      )
    );
    setSelectedConvUser({
      id: conv.other_user_id,
      type: conv.other_user_type,
      name: conv.other_user?.name || "Unknown",
      role: conv.other_user_type,
      avatar: "",
    });
  };

  const handleMarkImportant = () => {
    const updatedNotes = notes.map((note) =>
      note.id === selectedNote.id ? { ...note, important: !note.important } : note
    );
    setNotes(updatedNotes);
    setSelectedNote({ ...selectedNote, important: !selectedNote.important });
  };

  const handleDelete = () => {
    setNotes(notes.filter((note) => note.id !== selectedNote.id));
    setShowDeleteConfirm(false);
    setSelectedNote(null);
  };

  const handleArchive = () => {
    setNotes(notes.filter((note) => note.id !== selectedNote.id));
    setSelectedNote(null);
  };

  return (
    <div className="container-fluid p-0 h-100 d-flex flex-column mesage-social">
      <div className="d-flex flex-wrap align-items-center justify-content-between pb-3 bg-white">
        <div className="d-flex align-items-center gap-3 mb-2">
          <MessagesSquare strokeWidth={1.8} size={24} color="#ff3e43" />
          <h4>Messages from Shareholders</h4>
        </div>
        <button
          className="py-2 bg_primary creditb"
          onClick={() => setShowChatModal(true)}
          onMouseEnter={(e) => (e.currentTarget.style.backgroundColor = "#e0353a")}
          onMouseLeave={(e) => (e.currentTarget.style.backgroundColor = "#ff3e43")}
        >
          <MessageCircle size={18} />
          View All Messages
        </button>
      </div>

      {/* ✅ Filter tabs + Sort */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12, gap: 8 }}>
        {/* Tabs */}
        <div style={{ display: "flex", gap: 6 }}>
          <button
            onClick={() => setActiveTab("all")}
            style={{
              padding: "5px 14px", borderRadius: 20, border: "none", cursor: "pointer",
              fontSize: 12, fontWeight: 600,
              background: activeTab === "all" ? "#ff3e43" : "#f3f4f6",
              color: activeTab === "all" ? "#fff" : "#6b7280",
              transition: "all 0.15s",
            }}
          >
            All
          </button>
          <button
            onClick={() => setActiveTab("starred")}
            style={{
              padding: "5px 14px", borderRadius: 20, border: "none", cursor: "pointer",
              fontSize: 12, fontWeight: 600,
              background: activeTab === "starred" ? "#ff3e43" : "#f3f4f6",
              color: activeTab === "starred" ? "#fff" : "#6b7280",
              display: "flex", alignItems: "center", gap: 4,
              transition: "all 0.15s",
            }}
          >
            <Star size={11} fill={activeTab === "starred" ? "#fff" : "none"} />
            Starred {starredIds.size > 0 && `(${starredIds.size})`}
          </button>
        </div>

        {/* Sort button */}
        <button
          onClick={() => setSortOrder((prev) => (prev === "desc" ? "asc" : "desc"))}
          title={sortOrder === "desc" ? "Newest first" : "Oldest first"}
          style={{
            display: "flex", alignItems: "center", gap: 5,
            padding: "5px 12px", borderRadius: 20, border: "1px solid #e5e7eb",
            background: "#fff", cursor: "pointer", fontSize: 12,
            color: "#6b7280", fontWeight: 500,
          }}
        >
          {sortOrder === "desc" ? <ArrowDown size={13} /> : <ArrowUp size={13} />}
          {sortOrder === "desc" ? "Newest" : "Oldest"}
        </button>
      </div>

      <div className="bg-light custom_scroll" style={{ maxHeight: "calc(100vh - 160px)", overflowY: "auto" }}>
        <div className="list-group list-group-flush d-flex flex-column gap-2 bg-white">
          <div className="cards-stack">
            {convLoading ? (
              <div style={{ padding: "20px", textAlign: "center", color: "#9ca3af" }}>
                <div style={{ width: 24, height: 24, borderRadius: "50%", border: "3px solid #eef0f4", borderTopColor: "#ff3e43", animation: "spin .75s linear infinite", margin: "0 auto 8px" }} />
                Loading conversations...
              </div>
            ) : displayedConversations.length === 0 ? (
              <div style={{ padding: "30px", textAlign: "center", color: "#9ca3af", fontSize: 13 }}>
                {activeTab === "starred" ? (
                  <>
                    <Star size={28} color="#e5e7eb" style={{ marginBottom: 8 }} />
                    <div>No starred conversations yet</div>
                    <div style={{ fontSize: 11, marginTop: 4 }}>Click the ⭐ on any conversation to star it</div>
                  </>
                ) : "No conversations yet"}
              </div>
            ) : (
              displayedConversations.map((conv) => {
                const unread = getUnreadCount(conv);
                const otherName = conv.other_user?.name || "Unknown";
                const initial = otherName.charAt(0).toUpperCase();
                const roleColor = getRoleColor(conv.other_user_type);
                const lastMessage = conv.last_message || "Start a conversation";
                const lastMessageTime = conv.last_message_time || conv.updated_at;
                const isStarred = starredIds.has(conv.conversation_id);

                return (
                  <div
                    key={conv.conversation_id}
                    className="modern-card"
                    onClick={() => handleCardClick(conv)}
                    style={{ cursor: "pointer" }}
                  >
                    <div className="card-top">
                      <div className="user-meta">
                        {/* Avatar */}
                        <div className="avatar-wrapper" style={{ position: "relative", flexShrink: 0 }}>
                          <img
                            src={`https://ui-avatars.com/api/?name=${encodeURIComponent(otherName)}&background=${roleColor.replace("#", "")}&color=fff&bold=true`}
                            alt={otherName}
                            className="avatar-img"
                            style={{ width: 40, height: 40, borderRadius: "50%", objectFit: "cover" }}
                            onError={(e) => { e.target.style.display = "none"; e.target.nextSibling.style.display = "flex"; }}
                          />
                          <div style={{ width: 40, height: 40, borderRadius: "50%", background: `linear-gradient(135deg, ${roleColor}, ${roleColor}bb)`, color: "#fff", display: "none", alignItems: "center", justifyContent: "center", fontWeight: 700, fontSize: 16 }}>
                            {initial}
                          </div>
                          <div style={{ position: "absolute", bottom: 1, right: 1, width: 10, height: 10, borderRadius: "50%", background: isOnline(conv.other_user_id, conv.other_user_type) ? "#22c55e" : "#d1d5db", border: "2px solid #fff" }} />
                        </div>

                        {/* Text */}
                        <div className="text-group">
                          <div className="name-row" style={{ display: "flex", alignItems: "center", gap: 6, flexWrap: "wrap" }}>
                            <span className="sender-name" style={{ fontWeight: unread > 0 ? 700 : 500 }}>
                              {otherName}
                            </span>
                            <span className="dot-separator">•</span>
                            <span className="timestamp">{formatTime(lastMessageTime)}</span>
                            {unread > 0 && (
                              <span style={{ background: "#ff3e43", color: "#fff", fontSize: 10, fontWeight: 700, borderRadius: 20, padding: "2px 7px" }}>
                                {unread > 99 ? "99+" : unread}
                              </span>
                            )}
                          </div>
                          <div className="role-badge shareholder" style={{ display: "inline-flex", alignItems: "center", background: `${roleColor}18`, borderRadius: 4, padding: "2px 8px", marginTop: 2 }}>
                            <span className="label-type" style={{ fontSize: 11, color: roleColor, fontWeight: 500 }}>
                              {conv.other_user_type === "investor" ? "Investor" : conv.other_user_type === "company" ? "Company" : conv.other_user_type?.charAt(0).toUpperCase() + conv.other_user_type?.slice(1)}
                            </span>
                          </div>
                        </div>
                      </div>

                      {/* ✅ Star Button — functional */}
                      <button
                        className="star-btn"
                        onClick={(e) => handleStarConv(e, conv.conversation_id)}
                        title={isStarred ? "Unstar" : "Star this conversation"}
                        style={{
                          background: "none", border: "none", cursor: "pointer",
                          padding: 4, borderRadius: "50%",
                          display: "flex", alignItems: "center", justifyContent: "center",
                          color: isStarred ? "#f59e0b" : "#9ca3af",
                          transition: "color 0.15s, transform 0.1s",
                          transform: starLoading.has(conv.conversation_id) ? "scale(0.85)" : "scale(1)",
                        }}
                      >
                        <Star
                          size={18}
                          fill={isStarred ? "#f59e0b" : "none"}
                          stroke={isStarred ? "#f59e0b" : "#9ca3af"}
                        />
                      </button>
                    </div>

                    {/* Last Message */}
                    <div className="card-content">
                      <p style={{ margin: 0, fontSize: 13, color: unread > 0 ? "#374151" : "#6b7280", fontWeight: unread > 0 ? 500 : 400, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                        {lastMessage.length > 60 ? `${lastMessage.substring(0, 60)}...` : lastMessage}
                      </p>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </div>
      </div>

      {/* Note Modal */}
      {selectedNote && (
        <div className="modal fade show d-block message-view" tabIndex="-1" style={{ backgroundColor: "rgba(0,0,0,0.6)" }}>
          <div className="modal-dialog modal-dialog-centered modal-lg">
            <div className="modal-content border-0 shadow-lg rounded-3">
              <div className="modal-header border-0 pb-0 pt-4 px-4 d-flex align-items-start justify-content-between">
                <div className="d-flex flex-column gap-3">
                  <div className="d-flex align-items-center gap-2">
                    <button className="btn p-0 border-0" onClick={handleMarkImportant} style={{ color: selectedNote.important ? "#ff3e43" : "#adb5bd" }}>
                      <Star size={20} fill={selectedNote.important ? "#ff3e43" : "none"} stroke={selectedNote.important ? "#ff3e43" : "currentColor"} />
                    </button>
                    <h5 className="fw-semibold">{selectedNote.subject}</h5>
                  </div>
                  <div className="d-flex align-items-center gap-2 message-info">
                    <Mail size={18} /><p>{selectedNote.name}</p><p>•</p>
                    <p>{selectedNote.role}</p><p>•</p><p>{selectedNote.time}</p>
                  </div>
                </div>
                <button type="button" className="close_btn_pop" onClick={() => setSelectedNote(null)}><CircleX /></button>
              </div>
              <div className="modal-body px-4 py-4">
                <div className="message-main"><p>{selectedNote.body}</p></div>
              </div>
              <div className="modal-footer border-0 px-4 pb-4 pt-2 gap-2">
                <button className="py-2 su-creditb d-inline-flex align-items-center" onClick={handleArchive}><Archive size={16} className="me-2" /> Archive</button>
                <button className="py-2 creditb d-inline-flex align-items-center" style={{ backgroundColor: "#ff3e43", color: "white", border: "none" }} onClick={() => setShowDeleteConfirm(true)}><Trash2 size={16} className="me-2" /> Delete</button>
                <button className="py-2 creditb bg-success ms-auto d-inline-flex align-items-center"><Reply size={16} className="me-2" /> Respond</button>
              </div>
            </div>
          </div>
          {showDeleteConfirm && (
            <div style={{ position: "fixed", inset: 0, backgroundColor: "rgba(0,0,0,0.5)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 9999 }}>
              <div className="bg-white p-4 rounded-3 shadow-lg d-flex flex-column gap-3" style={{ maxWidth: "420px" }}>
                <div className="d-flex flex-column gap-2 message-info"><h6>Delete Note</h6><p>Are you sure you want to delete this note?</p></div>
                <div className="d-flex gap-2 justify-content-end">
                  <button className="py-2 su-creditb" onClick={() => setShowDeleteConfirm(false)}>Cancel</button>
                  <button className="py-2 creditb border-0 text-white" onClick={handleDelete} style={{ backgroundColor: "#ff3e43" }}>Yes, Delete</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {selectedConvUser && <ChatMessageModal onClose={handleCloseChat} currentUser={currentUser} selectedUser={selectedConvUser} />}
      {showChatModal && <ChatMessageAllModal onClose={handleCloseChatAll} currentUser={currentUser} />}

      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}